import time
from dataclasses import dataclass, field
from typing import Any, Dict, List, Optional


# Pricing per million tokens
MODEL_PRICING = {
    "gpt-4-turbo": {"input": 10.0, "output": 30.0},
    "gpt-4o": {"input": 2.5, "output": 10.0},
    "gpt-4o-mini": {"input": 0.15, "output": 0.60},
    "claude-3.5-sonnet": {"input": 3.0, "output": 15.0},
}


def calculate_llm_cost(model: str, input_tokens: int, output_tokens: int) -> float:
    """Calculate cost in USD for a single LLM call."""
    if model not in MODEL_PRICING:
        raise ValueError(f"Unknown model: {model}")
    pricing = MODEL_PRICING[model]
    cost = (input_tokens * pricing["input"] + output_tokens * pricing["output"]) / 1_000_000
    return cost


@dataclass
class Span:
    name: str
    span_type: str
    start_time: float = 0.0
    end_time: float = 0.0
    attributes: Dict[str, Any] = field(default_factory=dict)
    children: List['Span'] = field(default_factory=list)
    parent: Optional['Span'] = None

    @property
    def duration_ms(self) -> float:
        """Return span duration in milliseconds."""
        return (self.end_time - self.start_time) * 1000

    @property
    def total_cost(self) -> float:
        """Return cost of this span plus all descendant spans."""
        own_cost = self.attributes.get('cost_usd', 0.0)
        child_cost = sum(child.total_cost for child in self.children)
        return own_cost + child_cost


class Tracer:
    def __init__(self, trace_id: str):
        self.trace_id = trace_id
        self.root_span: Optional[Span] = None
        self._current_span: Optional[Span] = None

    def start_span(self, name: str, span_type: str, attributes: Dict[str, Any] = None) -> Span:
        """Create and enter a new span, nested under current span if one exists."""
        span = Span(
            name=name,
            span_type=span_type,
            start_time=time.time(),
            attributes=attributes or {},
            parent=self._current_span,
        )
        if self.root_span is None:
            self.root_span = span
        if self._current_span is not None:
            self._current_span.children.append(span)
        self._current_span = span
        return span

    def end_span(self) -> None:
        """Close the current span and return to parent."""
        if self._current_span is not None:
            self._current_span.end_time = time.time()
            self._current_span = self._current_span.parent

    def get_all_spans(self) -> List[Span]:
        """Return flat list of all spans in depth-first order."""
        if self.root_span is None:
            return []
        result = []
        stack = [self.root_span]
        while stack:
            span = stack.pop()
            result.append(span)
            # Push children in reverse order so leftmost child is processed first
            for child in reversed(span.children):
                stack.append(child)
        return result

    @property
    def total_duration_ms(self) -> float:
        """Return root span's duration in ms."""
        if self.root_span is None:
            return 0.0
        return self.root_span.duration_ms

    @property
    def total_cost(self) -> float:
        """Return sum of all cost_usd attributes across all spans."""
        return sum(s.attributes.get('cost_usd', 0.0) for s in self.get_all_spans())

from typing import Optional
import re


def split_sentences(text: str) -> list:
    """Split text into sentences."""
    # Split on sentence-ending punctuation followed by space or end of string
    parts = re.split(r'(?<=[.!?])\s+', text.strip())
    return [s.strip() for s in parts if s.strip()]


def get_content_words(text: str, min_length: int = 4) -> set:
    """Extract content words (lowercase, minimum length) from text."""
    words = re.findall(r'[a-zA-Z]+', text.lower())
    return {w for w in words if len(w) >= min_length}


def score_faithfulness(response: str, context: str) -> float:
    """Score how faithful the response is to the provided context."""
    sentences = split_sentences(response)
    if not sentences:
        return 1.0

    context_words = get_content_words(context, min_length=4)
    if not context_words:
        return 0.0

    supported_count = 0
    for sentence in sentences:
        sentence_words = get_content_words(sentence, min_length=4)
        if not sentence_words:
            supported_count += 1  # trivial sentence counts as supported
            continue
        overlap = sentence_words & context_words
        if len(overlap) / len(sentence_words) >= 0.5:
            supported_count += 1

    return supported_count / len(sentences)


def score_answer_relevancy(response: str, query: str) -> float:
    """Score how relevant the response is to the query."""
    query_words = get_content_words(query, min_length=3)
    response_words = get_content_words(response, min_length=3)

    if not query_words or not response_words:
        return 0.0

    # Word overlap coefficient: |intersection| / |smaller set|
    intersection = query_words & response_words
    overlap_coeff = len(intersection) / min(len(query_words), len(response_words))

    # Length penalty for verbose responses
    query_len = len(query.split())
    response_len = len(response.split())
    if response_len > 3 * query_len and response_len > 0:
        overlap_coeff *= (3 * query_len / response_len)

    return min(overlap_coeff, 1.0)


def score_context_relevancy(context: str, query: str) -> float:
    """Score how much of the context is relevant to the query."""
    sentences = split_sentences(context)
    if not sentences:
        return 0.0

    query_words = get_content_words(query, min_length=3)
    if not query_words:
        return 0.0

    relevant_count = 0
    for sentence in sentences:
        sentence_words = get_content_words(sentence, min_length=3)
        overlap = sentence_words & query_words
        if len(overlap) / len(query_words) >= 0.3:
            relevant_count += 1

    return relevant_count / len(sentences)


def evaluate_rag(
    query: str,
    context: str,
    response: str,
    reference: Optional[str] = None,
) -> dict:
    """Run full RAGAS-style evaluation. Returns dict of metric scores."""
    metrics = {
        'faithfulness': score_faithfulness(response, context),
        'answer_relevancy': score_answer_relevancy(response, query),
        'context_relevancy': score_context_relevancy(context, query),
    }

    if reference is not None:
        ref_words = get_content_words(reference, min_length=4)
        context_words = get_content_words(context, min_length=4)
        if ref_words:
            metrics['context_recall'] = len(ref_words & context_words) / len(ref_words)
        else:
            metrics['context_recall'] = 1.0

    metrics['overall'] = sum(metrics.values()) / len(metrics)
    return metrics

from dataclasses import dataclass, field
from typing import Callable, Dict, List, Optional
from collections import defaultdict


@dataclass
class EvalCase:
    id: str
    query: str
    context: str = ''
    reference: str = ''
    category: str = 'general'
    required_facts: list = field(default_factory=list)
    forbidden_content: list = field(default_factory=list)


@dataclass
class EvalMetric:
    name: str
    score_fn: Callable
    threshold: float = 0.5


@dataclass
class CaseResult:
    case_id: str
    category: str
    response: str
    scores: Dict[str, float] = field(default_factory=dict)
    passed: bool = False


class EvalPipeline:
    def __init__(self, metrics: List[EvalMetric]):
        self.metrics = metrics

    def run(self, cases: List[EvalCase], system_fn: Callable) -> dict:
        """Run eval cases through system, score, and produce report."""
        results = []

        for case in cases:
            # Run system
            response = system_fn(case.query, case.context)

            # Score with all metrics
            scores = {}
            for metric in self.metrics:
                score = metric.score_fn(
                    response=response,
                    query=case.query,
                    context=case.context,
                    reference=case.reference,
                    required_facts=case.required_facts,
                    forbidden_content=case.forbidden_content,
                )
                scores[metric.name] = score

            # Pass/fail: all metrics must meet threshold
            passed = all(
                scores.get(m.name, 0) >= m.threshold
                for m in self.metrics
            )

            results.append(CaseResult(
                case_id=case.id,
                category=case.category,
                response=response,
                scores=scores,
                passed=passed,
            ))

        # Aggregate
        total = len(results)
        passed = sum(1 for r in results if r.passed)

        # Average scores per metric
        avg_scores = {}
        for metric in self.metrics:
            metric_scores = [r.scores[metric.name] for r in results]
            avg_scores[metric.name] = sum(metric_scores) / len(metric_scores) if metric_scores else 0.0

        # By category
        by_category = defaultdict(lambda: {"total": 0, "passed": 0})
        for r in results:
            by_category[r.category]["total"] += 1
            if r.passed:
                by_category[r.category]["passed"] += 1

        by_category_final = {}
        for cat, stats in by_category.items():
            by_category_final[cat] = {
                "total": stats["total"],
                "passed": stats["passed"],
                "pass_rate": stats["passed"] / stats["total"] if stats["total"] > 0 else 0.0,
            }

        return {
            "total": total,
            "passed": passed,
            "pass_rate": passed / total if total > 0 else 0.0,
            "avg_scores": avg_scores,
            "by_category": by_category_final,
            "results": results,
        }


def detect_regression(
    baseline_report: dict,
    candidate_report: dict,
    tolerance: float = 0.05,
) -> dict:
    """Compare two eval reports and detect metric regressions."""
    regressions = []

    baseline_scores = baseline_report.get("avg_scores", {})
    candidate_scores = candidate_report.get("avg_scores", {})

    for metric_name in baseline_scores:
        if metric_name in candidate_scores:
            baseline_val = baseline_scores[metric_name]
            candidate_val = candidate_scores[metric_name]
            delta = candidate_val - baseline_val

            if delta < -tolerance:
                regressions.append({
                    "metric": metric_name,
                    "baseline": baseline_val,
                    "candidate": candidate_val,
                    "delta": delta,
                })

    return {
        "regressed": len(regressions) > 0,
        "regressions": regressions,
    }
